   139→// Orchestrate command
   140→program
   141→  .command('orchestrate [features-path]')
   142→  .description('Run full orchestration with parallel agents')
   143→  .option('-n, --max-agents <number>', 'Maximum concurrent agents', '3')
   144→  .option('-m, --model <model>', 'Default model (haiku, sonnet, opus)', 'sonnet')
   145→  .option('--dry-run', 'Show plan without executing')
   146→  .option('--timeout <ms>', 'Timeout per task in milliseconds', '600000')
   147→  .option('-d, --dashboard', 'Enable real-time dashboard UI')
   148→  .option('--no-costs', 'Disable cost estimates in dashboard')
   149→  .action(async (featuresPath: string | undefined, options) => {
   150→    const spinner = ora('Loading harness configuration...').start();
   151→
   152→    try {
   153→      const resolvedPath = resolveFeaturesPath(featuresPath);
   154→      const stateManager = new StateManager(resolvedPath);
   155→      const config = stateManager.load();
   156→
   157→      spinner.succeed('Configuration loaded');
   158→
   159→      const pending = config.features.filter((f) => !f.passes).length;
   160→
   161→      if (options.dryRun) {
   162→        console.log(chalk.yellow('\n🔍 Dry Run Mode\n'));
   163→        console.log('Would orchestrate with:');
   164→        console.log(`  Max agents: ${options.maxAgents}`);
   165→        console.log(`  Model: ${options.model}`);
   166→        console.log(`  Features: ${pending} pending`);
   167→        console.log(`  Dashboard: ${options.dashboard ? 'enabled' : 'disabled'}`);
   168→        return;
   169→      }
   170→
   171→      if (pending === 0) {
   172→        console.log(chalk.green('\n✅ All features are already complete!'));
   173→        return;
   174→      }
   175→
   176→      const orchestrator = new Orchestrator(resolvedPath, {
   177→        maxAgents: parseInt(options.maxAgents, 10),
   178→        model: options.model as ModelType,
   179→        timeout: parseInt(options.timeout, 10),
   180→      });
   181→
   182→      if (options.dashboard) {
   183→        // Use real-time dashboard
   184→        const dashboard = new Dashboard(config, {
   185→          liveRefresh: true,
   186→          showCosts: options.costs !== false,
   187→          maxAgents: parseInt(options.maxAgents, 10),
   188→        });
   189→        dashboard.setModel(options.model as 'haiku' | 'sonnet' | 'opus');
   190→        dashboard.attach(orchestrator);
   191→
   192→        const result = await orchestrator.run();
   193→        dashboard.renderFinalSummary();
   194→
   195→        if (result.failed > 0) {
   196→          process.exit(1);
   197→        }
   198→      } else {
   199→        // Classic output mode
   200→        console.log(chalk.bold('\n🚀 Starting Orchestration\n'));
   201→        console.log(`  Max agents: ${chalk.cyan(options.maxAgents)}`);
   202→        console.log(`  Model: ${chalk.cyan(options.model)}`);
   203→        console.log(`  Pending: ${chalk.yellow(pending)} features`);
   204→        console.log();
   205→
   206→        // Event handlers for progress display
   207→        orchestrator.on('taskDispatched', ({ taskId, feature }) => {
   208→          console.log(chalk.blue(`▶ Started ${taskId}: ${feature.description}`));
   209→        });
   210→
   211→        orchestrator.on('taskSucceeded', ({ taskId }) => {
   212→          console.log(chalk.green(`✓ Completed ${taskId}`));
   213→        });
   214→
   215→        orchestrator.on('taskFailed', ({ taskId, error }) => {
   216→          console.log(chalk.red(`✗ Failed ${taskId}: ${error}`));
   217→        });
   218→
   219→        orchestrator.on('deadlock', ({ pending }) => {
   220→          console.log(chalk.red(`\n⚠️  Deadlock detected! ${pending} tasks stuck.`));
   221→        });
   222→
   223→        orchestrator.on('shutdown', ({ signal }) => {
   224→          console.log(chalk.yellow(`\n⚠️  Received ${signal}, shutting down gracefully...`));
   225→        });
   226→
   227→        const runSpinner = ora('Running orchestration...').start();
   228→        const result = await orchestrator.run();
   229→        runSpinner.stop();
   230→
   231→        console.log(chalk.bold('\n📊 Results\n'));
   232→        console.log(`  Completed: ${chalk.green(result.completed)}`);
   233→        console.log(`  Failed: ${chalk.red(result.failed)}`);
   234→
   235→        if (result.failed === 0) {
   236→          console.log(chalk.green('\n✅ Orchestration completed successfully!'));
   237→        } else {
   238→          console.log(chalk.yellow(`\n⚠️  ${result.failed} task(s) failed.`));
   239→          process.exit(1);
   240→        }
   241→      }
   242→    } catch (error) {
   243→      spinner.fail('Orchestration failed');
   244→      console.error(error);
   245→      process.exit(1);
   246→    }
   247→  });
