      const sessionStartPath = resolve(hooksDir, 'session-start.sh');
      if (!existsSync(sessionStartPath)) {
        const sessionStartTemplate = `#!/bin/bash
# Session Start Hook - runs at the beginning of each Claude session

echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
echo "🚀 HARNESS SESSION START"
echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
echo ""
echo "📅 Current date: $(date +%Y-%m-%d)"
echo ""
echo "┌─────────────────────────────────────────────┐"
echo "│ WORK PROTOCOL                               │"
echo "├─────────────────────────────────────────────┤"
echo "│ 1. READ claude-progress.txt                 │"
echo "│ 2. READ features.json (find passes:false)   │"
echo "│ 3. IMPLEMENT one feature                    │"
echo "│ 4. TEST the implementation                  │"
echo "│ 5. COMMIT after feature passes              │"
echo "│ 6. UPDATE claude-progress.txt               │"
echo "└─────────────────────────────────────────────┘"
echo ""
`;
        writeFileSync(sessionStartPath, sessionStartTemplate);
        const { chmodSync } = await import('node:fs');
        chmodSync(sessionStartPath, '755');
        console.log(chalk.green('✓ Created .claude/hooks/session-start.sh'));
      }
    }

    // 6. Initialize git (if not --no-git)
    if (options.git !== false) {
      const gitDir = resolve(targetDir, '.git');
      if (!existsSync(gitDir)) {
        const { execSync } = await import('node:child_process');
        try {
          execSync('git init', { cwd: targetDir, stdio: 'pipe' });
          console.log(chalk.green('✓ Initialized git repository'));
        } catch {
          console.log(chalk.yellow('○ Could not initialize git'));
        }
      } else {
        console.log(chalk.yellow('○ Git already initialized'));
      }
    }

    console.log(chalk.bold.green('\n✅ Harness initialized successfully!\n'));
